import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"尋找可信賴的模組","description":"本指南教你如何使用可信賴的來源找到 Fabric 模組。","frontmatter":{"title":"尋找可信賴的模組","description":"本指南教你如何使用可信賴的來源找到 Fabric 模組。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.1/players/finding-mods.md","filePath":"versions/1.21.1/translated/zh_tw/players/finding-mods.md","lastUpdated":1761424914000}`);var a={name:`zh_tw/1.21.1/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">尋找可信賴的模組 <a class="header-anchor" href="#h1" aria-label="Permalink to “尋找可信賴的模組”">​</a></h1><p>首先，信任是主觀的，當下載模組時你應該始終根據自己的判斷。 但是，有一些方法可以幫助您找到可信任的模組。</p><h2 id="_1-使用眾所周知的可信任來源" tabindex="-1">1. 使用眾所周知的可信任來源 <a class="header-anchor" href="#_1-使用眾所周知的可信任來源" aria-label="Permalink to “1. 使用眾所周知的可信任來源”">​</a></h2><p>大部分作者會將他們的模組發布到 <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> 和 <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>。</p><p>這些網站會檢查模組是否符合其宣稱，並且不含有惡意程式碼。 你也可以在這些網站上回報惡意模組，他們會相對迅速地採取行動。</p><h2 id="with-others" tabindex="-1">2. 與其他人確認！ <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. 與其他人確認！”">​</a></h2><p>如果你從不被認為是可信任的來源下載模組，你應該與他人討論，看看他們是否曾經從你下載的位置下載過模組，以及他們是否遇到過任何問題。</p><p>如果你有疑問，歡迎在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 頻道中詢問。</p><h2 id="avoid-malware" tabindex="-1">3. 避免常見的惡意軟體網站！ <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. 避免常見的惡意軟體網站！”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>惡意軟體網站對於每個人來說可能不是很明顯。 如果您不確定，你應該向他人尋求意見，或者完全避免該網站，僅依賴於可信任的來源，例如 Modrinth 和 CurseForge。</p></div><p>有許多聲稱提供 Minecraft 模組的網站，實際上只是惡意軟體網站。 你應該盡量避免這些網站。</p><p>你可以使用防病毒軟體和像 <a href="https://www.microsoft.com/zh-tw/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> 或 <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> 這樣的網站來檢查下載的模組。 但是，不要完全依賴這些方法，因為有時候它們可能不準確。</p><p>同樣地，如果你有疑問，歡迎在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 頻道中尋求意見。</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};